patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index cad17c511b6d..597771f3e306 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -284,7 +284,7 @@ bool InstCombinerImpl::shouldChangeType(Type *From, Type *To) const {
 // not overflow. This function only handles the Add/Sub/Mul opcodes. For
 // all other opcodes, the function conservatively returns false.
 static bool maintainNoSignedWrap(BinaryOperator &I, Value *B, Value *C) {
-  auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
+  auto *OBO = (isa<OverflowingBinaryOperator>(&I) ? cast<OverflowingBinaryOperator>(&I) : nullptr);
   if (!OBO || !OBO->hasNoSignedWrap())
     return false;

@@ -312,12 +312,12 @@ static bool maintainNoSignedWrap(BinaryOperator &I, Value *B, Value *C) {
 }

 static bool hasNoUnsignedWrap(BinaryOperator &I) {
-  auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
+  auto *OBO = (isa<OverflowingBinaryOperator>(&I) ? cast<OverflowingBinaryOperator>(&I) : nullptr);
   return OBO && OBO->hasNoUnsignedWrap();
 }

 static bool hasNoSignedWrap(BinaryOperator &I) {
-  auto *OBO = dyn_cast<OverflowingBinaryOperator>(&I);
+  auto *OBO = (isa<OverflowingBinaryOperator>(&I) ? cast<OverflowingBinaryOperator>(&I) : nullptr);
   return OBO && OBO->hasNoSignedWrap();
 }

@@ -739,12 +739,12 @@ static Value *tryFactorization(BinaryOperator &I, const SimplifyQuery &SQ,
       HasNSW = I.hasNoSignedWrap();
       HasNUW = I.hasNoUnsignedWrap();
     }
-    if (auto *LOBO = dyn_cast<OverflowingBinaryOperator>(LHS)) {
+    if (auto *LOBO = dyn_cast_or_null<OverflowingBinaryOperator>(LHS)) {
       HasNSW &= LOBO->hasNoSignedWrap();
       HasNUW &= LOBO->hasNoUnsignedWrap();
     }

-    if (auto *ROBO = dyn_cast<OverflowingBinaryOperator>(RHS)) {
+    if (auto *ROBO = dyn_cast_or_null<OverflowingBinaryOperator>(RHS)) {
       HasNSW &= ROBO->hasNoSignedWrap();
       HasNUW &= ROBO->hasNoUnsignedWrap();
     }
@@ -759,10 +759,10 @@ static Value *tryFactorization(BinaryOperator &I, const SimplifyQuery &SQ,
       // iff C+1 isn't INT_MIN
       const APInt *CInt;
       if (match(V, m_APInt(CInt)) && !CInt->isMinSignedValue())
-        cast<Instruction>(RetVal)->setHasNoSignedWrap(HasNSW);
+        if (auto *RI = dyn_cast<Instruction>(RetVal)) RI->setHasNoSignedWrap(HasNSW);

       // nuw can be propagated with any constant or nuw value.
-      cast<Instruction>(RetVal)->setHasNoUnsignedWrap(HasNUW);
+      if (auto *RI = dyn_cast<Instruction>(RetVal)) RI->setHasNoUnsignedWrap(HasNUW);
     }
   }
   return RetVal;

